          if !comp { return false }
        }
        else { result = nil }
        return result
      }


      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(
        ID: tIDENTIFIER, 
        NAME: tLABEL, 
        DESCRIPTION: tTEXT? , 
        RELATING_PRODUCT: ePRODUCT.PRef, 
        RELATED_PRODUCT: ePRODUCT.PRef
      ) {

        self._id = ID
        self._name = NAME
        self._description = DESCRIPTION
        self._relating_product = RELATING_PRODUCT
        self._related_product = RELATED_PRODUCT

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( ID: original._id, NAME: original._name, DESCRIPTION: original._description, RELATING_PRODUCT: original._relating_product, RELATED_PRODUCT: original._related_product )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 5
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: tIDENTIFIER.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]ID for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: tLABEL.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]NAME for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverOptionalParameter(as: tTEXT.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]DESCRIPTION for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p3) = exchangeStructure.recoverRequiredParameter(as: ePRODUCT.PRef.self, from: parameters[3])
        else { exchangeStructure.add(errorContext: "while recovering parameter [3]RELATING_PRODUCT for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p4) = exchangeStructure.recoverRequiredParameter(as: ePRODUCT.PRef.self, from: parameters[4])
        else { exchangeStructure.add(errorContext: "while recovering parameter [4]RELATED_PRODUCT for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( ID: p0, NAME: p1, DESCRIPTION: p2, RELATING_PRODUCT: p3, RELATED_PRODUCT: p4 )
      }
    }
  }
